// Arma un resumen legible a partir del overview real.
const o = ($json.data) || {};
const resumen = [
  `Leads totales: ${o.leads_total ?? 0}`,
  `Leads calientes: ${o.hot_leads ?? 0}`,
  `Conversaciones: ${o.conversations_total ?? 0}`,
  `Seguimientos pendientes: ${o.pending_followups ?? 0}`,
  `Convertidos: ${o.converted_leads ?? 0}`,
  `Ingresos atribuidos: ${o.revenue_total ?? 0}`,
  `ROAS: ${o.roas ?? '-'}`,
  `Acciones IA: ${o.ai_actions_count ?? 0}`,
  `Control humano: ${o.human_takeover_count ?? 0}`
].join(' | ');
return [{ json: { resumen, overview: o, generated_at: new Date().toISOString() } }];
